namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Custom header injection filter configuration.
 * Stores header injection rules for requests and responses.
 */
class Config : public ::Envoy::Router::RouteSpecificFilterConfig,
               public Logger::Loggable<Logger::Id::config> {
public:
  /**
   * Represents a header injection rule.
   */
  struct HeaderInjectionRule {
    std::string header_name;
    std::string header_value;
  };

  using HeaderInjectionRules = std::vector<HeaderInjectionRule>;

  Config(const HeaderInjectionRules& request_rules, const HeaderInjectionRules& response_rules)
      : request_rules_(request_rules), response_rules_(response_rules) {}

  const HeaderInjectionRules& requestRules() const { return request_rules_; }
  const HeaderInjectionRules& responseRules() const { return response_rules_; }
  bool hasRequestRules() const { return !request_rules_.empty(); }
  bool hasResponseRules() const { return !response_rules_.empty(); }

private:
  const HeaderInjectionRules request_rules_;
  const HeaderInjectionRules response_rules_;
};

using ConfigSharedPtr = std::shared_ptr<Config>;

/**
 * Custom Header Injection filter that injects configurable headers into
 * requests and/or responses based on configuration.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                   public Logger::Loggable<Logger::Id::filter> {
public:
  CustomHeaderInjectionFilter(const ConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;

  // StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;

private:
  const ConfigSharedPtr config_;
  mutable const Config* effective_config_{nullptr};
  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};

  /**
   * Injects headers based on the provided rules.
   * @param headers the header map to inject headers into
   * @param rules the header injection rules
   */
  void injectHeaders(Http::HeaderMap& headers, const Config::HeaderInjectionRules& rules);

  /**
   * Gets the effective config, considering route-specific overrides.
   * @return the effective configuration
   */
  const Config* getConfig() const;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

