#pragma once

#include <string>
#include <vector>

#include "envoy/http/filter.h"
#include "envoy/server/filter_config.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Custom header injection filter configuration.
 * Stores header injection rules for requests and responses.
 */
class Config : public ::Envoy::Router::RouteSpecificFilterConfig,
               public Logger::Loggable<Logger::Id::config> {
public:
  /**
   * Represents a header injection rule.
   */
  struct HeaderInjectionRule {
    std::string header_name;
    std::string header_value;
  };

  using HeaderInjectionRules = std::vector<HeaderInjectionRule>;

  Config(const HeaderInjectionRules& request_rules, const HeaderInjectionRules& response_rules)
      : request_rules_(request_rules), response_rules_(response_rules) {}

  const HeaderInjectionRules& requestRules() const { return request_rules_; }
  const HeaderInjectionRules& responseRules() const { return response_rules_; }
  bool hasRequestRules() const { return !request_rules_.empty(); }
  bool hasResponseRules() const { return !response_rules_.empty(); }

private:
  const HeaderInjectionRules request_rules_;
  const HeaderInjectionRules response_rules_;
};

using ConfigSharedPtr = std::shared_ptr<Config>;

/**
 * Custom Header Injection filter that injects configurable headers into
 * requests and/or responses based on configuration.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                   public Logger::Loggable<Logger::Id::filter> {
public:
  CustomHeaderInjectionFilter(const ConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
