#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "envoy/http/utility.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    : config_(config) {}

CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;

Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers,
                                                                     bool) {
  const auto* config = getConfig();
  if (config->hasRequestRules()) {
    injectHeaders(headers, config->requestRules());
  }

  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    Http::StreamDecoderFilterCallbacks& callbacks) {
  decoder_callbacks_ = &callbacks;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
                                                                     bool) {
  const auto* config = getConfig();
  if (config->hasResponseRules()) {
    injectHeaders(headers, config->responseRules());
  }

  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    Http::StreamEncoderFilterCallbacks& callbacks) {
  encoder_callbacks_ = &callbacks;
}

void CustomHeaderInjectionFilter::injectHeaders(Http::HeaderMap& headers,
                                                const Config::HeaderInjectionRules& rules) {
  for (const auto& rule : rules) {
    headers.setReference(Http::LowerCaseString(rule.header_name), rule.header_value);
  }
}

const Config* CustomHeaderInjectionFilter::getConfig() const {
  // Cached config pointer.
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ = Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ = config_.get();
  return effective_config_;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

