#include <memory>

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "source/common/http/header_map_impl.h"

#include "test/mocks/http/mocks.h"
#include "test/mocks/stream_info/mocks.h"
#include "test/test_common/utility.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  void initializeFilter(const Config::HeaderInjectionRules& request_rules,
                        const Config::HeaderInjectionRules& response_rules) {
    config_ = std::make_shared<Config>(request_rules, response_rules);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  ConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  NiceMock<Envoy::StreamInfo::MockStreamInfo> stream_info_;
};

/**
 * Test basic request header injection.
 */
TEST_F(CustomHeaderInjectionFilterTest, BasicRequestHeaderInjection) {
  Config::HeaderInjectionRules request_rules = {
      {{"X-Custom-Header", "custom-value"}, {"X-Another-Header", "another-value"}}};

  initializeFilter(request_rules, {});

  Http::TestRequestHeaderMapImpl incoming_headers{{"content-type", "application/json"}};

  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(stream_info_));

  auto status = filter_->decodeHeaders(incoming_headers, false);

  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(incoming_headers.get("X-Custom-Header"), "custom-value");
  EXPECT_EQ(incoming_headers.get("X-Another-Header"), "another-value");
}

/**
 * Test basic response header injection.
 */
TEST_F(CustomHeaderInjectionFilterTest, BasicResponseHeaderInjection) {
  Config::HeaderInjectionRules response_rules = {
      {{"X-Response-Header", "response-value"}, {"X-Status-Header", "success"}}};

  initializeFilter({}, response_rules);

  Http::TestResponseHeaderMapImpl incoming_headers{{":status", "200"}};

  EXPECT_CALL(encoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(stream_info_));

  auto status = filter_->encodeHeaders(incoming_headers, false);

  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(incoming_headers.get("X-Response-Header"), "response-value");
  EXPECT_EQ(incoming_headers.get("X-Status-Header"), "success");
}

/**
 * Test both request and response header injection.
 */
TEST_F(CustomHeaderInjectionFilterTest, RequestAndResponseHeaderInjection) {
  Config::HeaderInjectionRules request_rules = {{{"X-Request-Id", "12345"}}};
  Config::HeaderInjectionRules response_rules = {{{"X-Processed", "true"}}};

  initializeFilter(request_rules, response_rules);

  // Test request
  Http::TestRequestHeaderMapImpl request_headers{};
  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(stream_info_));

  auto request_status = filter_->decodeHeaders(request_headers, false);
  EXPECT_EQ(request_status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(request_headers.get("X-Request-Id"), "12345");

  // Test response
  Http::TestResponseHeaderMapImpl response_headers{{":status", "200"}};
  EXPECT_CALL(encoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(stream_info_));

  auto response_status = filter_->encodeHeaders(response_headers, false);
  EXPECT_EQ(response_status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(response_headers.get("X-Processed"), "true");
}

/**
 * Test filter with no rules.
 */
TEST_F(CustomHeaderInjectionFilterTest, NoRules) {
  initializeFilter({}, {});

  Http::TestRequestHeaderMapImpl request_headers{{"content-type", "application/json"}};
  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(stream_info_));

  auto status = filter_->decodeHeaders(request_headers, false);
  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(request_headers.get("X-Custom-Header"), absl::nullopt);
}

/**
 * Test that filter returns Continue for data and trailers.
 */
TEST_F(CustomHeaderInjectionFilterTest, DataAndTrailersPass) {
  initializeFilter({}, {});

  Buffer::OwnedImpl data;
  EXPECT_EQ(filter_->decodeData(data, false), Http::FilterDataStatus::Continue);
  EXPECT_EQ(filter_->encodeData(data, false), Http::FilterDataStatus::Continue);

  Http::RequestTrailerMap trailers;
  EXPECT_EQ(filter_->decodeTrailers(trailers), Http::FilterTrailersStatus::Continue);

  Http::ResponseTrailerMap response_trailers;
  EXPECT_EQ(filter_->encodeTrailers(response_trailers), Http::FilterTrailersStatus::Continue);
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

